import React from 'react';
import Logo from './Logo.png'; 
import Menu from './Menu'; 

function App() {
  return (
    <div style={{ 
      backgroundColor: '#000', 
      minHeight: '100vh', 
      color: '#fff', 
      fontFamily: 'Arial, sans-serif',
      margin: 0,
      padding: 0
    }}>
      
      {/* 1. THE BIG HEADER (HERO SECTION) */}
      <header style={{ 
        width: '100%',
        height: '80vh',           // Makes the logo fill 80% of the screen height
        display: 'flex',
        flexDirection: 'column',
        justifyContent: 'center', 
        alignItems: 'center',       
        backgroundColor: '#000',    
        position: 'relative',
        overflow: 'hidden'
      }}>
        
        {/* THE LOGO - FIXED FOR STAINS/PATCHES */}
        <img 
          src={Logo} 
          alt="Àmí by T Logo" 
          style={{ 
            width: '90%',           
            maxWidth: '700px',      
            height: 'auto',         
            /* MAGIC TRICK: This hides any background stains/marks on the image */
            mixBlendMode: 'screen', 
            filter: 'brightness(1.1) drop-shadow(0 0 20px rgba(212, 175, 55, 0.4))',
            marginBottom: '40px'
          }} 
        />

        {/* BRANDS TAGLINE */}
        <div style={{ textAlign: 'center', zIndex: 10 }}>
          <h2 style={{ 
            color: '#D4AF37', 
            letterSpacing: '12px', 
            fontSize: '1.2rem', 
            textTransform: 'uppercase',
            margin: '0 0 10px 0',
            fontWeight: '300'
          }}>
            Taste and Style
          </h2>
          <div style={{ 
            width: '80px', 
            height: '1px', 
            backgroundColor: '#E07A5F', 
            margin: '0 auto' 
          }}></div>
        </div>

        {/* Subtle Scroll Indicator */}
        <div style={{ 
          position: 'absolute', 
          bottom: '30px', 
          color: '#444', 
          fontSize: '0.7rem', 
          letterSpacing: '3px' 
        }}>
          SCROLL TO EXPLORE
        </div>
      </header>

      {/* 2. THE MENU SECTION */}
      <main style={{ padding: '20px 0' }}>
        <Menu />
      </main>

      {/* 3. FOOTER */}
      <footer style={{ 
        textAlign: 'center', 
        padding: '60px 20px', 
        borderTop: '1px solid #111',
        color: '#333',
        fontSize: '0.7rem',
        letterSpacing: '2px'
      }}>
        <p>© 2026 ÀMÍ BY T | LAGOS, NIGERIA</p>
      </footer>
      
    </div>
  );
}

export default App;
